        processor.addProduct("Dick", 20);

        // Process an order string
        String orderString = "Niggerdick–10–10";
        int totalPrice = processor.calculateTotalPrice(orderString);

        System.out.println("Total Price: " + totalPrice); // Output: Total Price: 200
    }
}
```

